// N02 — Validar webhook key y número autorizado
const item = $input.first();
const headers = item.json.headers || {};
const body = (item.json.event !== undefined) ? item.json : (item.json.body || item.json);
const webhookKey = (headers['x-webhook-key'] || '').trim();
const expectedKey = ($env.N8N_WEBHOOK_KEY || 'soa_wh_0176ebabe2b446a3fe6f00773174f88d').trim();
const autorizado = ($env.WA_NUMERO_AUTORIZADO || '573232456846').replace('+','').replace(/\s/g,'').trim();
console.log('[N02] webhookKey:', webhookKey, '| match:', webhookKey === expectedKey);
if (!webhookKey || webhookKey !== expectedKey) { console.log('[N02] BLOQUEADO: key inválida'); return []; }
const data = body.data || {};
const key = data.key || {};
if (key.fromMe === true) return [];
const remoteJid = (key.remoteJid || '').toString();
const numero = remoteJid.replace('@s.whatsapp.net','').replace('@c.us','').replace('+','').trim();
console.log('[N02] número:', numero, '| autorizado:', autorizado);
if (!numero || numero !== autorizado) { console.log('[N02] BLOQUEADO: número no autorizado'); return []; }
console.log('[N02] OK');
return [{json: {...item.json, _body: body}}];

// N03 — Extraer y clasificar mensaje WhatsApp
const item = $input.first();
const body = item.json._body || item.json.body || item.json;
const data = body.data || {};
const key = data.key || {};
const message = data.message || {};
const remoteJid = (key.remoteJid || '').toString();
const remitente = remoteJid.replace('@s.whatsapp.net','').replace('@c.us','');
const timestamp = data.messageTimestamp || Math.floor(Date.now()/1000);
let texto = '', tipo_mensaje = 'texto', audio_base64 = '', audio_mimetype = 'audio/ogg';
if (message.conversation) { texto = message.conversation; }
else if (message.extendedTextMessage) { texto = message.extendedTextMessage.text || ''; }
else if (message.audioMessage) { tipo_mensaje = 'audio'; audio_base64 = data.message?.base64 || ''; audio_mimetype = message.audioMessage.mimetype || 'audio/ogg'; }
else if (message.imageMessage) { texto = message.imageMessage.caption || '[imagen]'; }
else if (message.documentMessage) { texto = (message.documentMessage.caption || message.documentMessage.fileName || 'doc').trim(); }
else if (message.videoMessage) { texto = message.videoMessage.caption || '[video]'; }
texto = texto.trim();
let comando_especial = null;
const tu = texto.toUpperCase();
if (tu === 'REINICIAR') comando_especial = 'REINICIAR';
else if (tu === 'ROLLBACK') comando_especial = 'ROLLBACK';
else if (tu === 'STOP') comando_especial = 'STOP';
if (comando_especial) tipo_mensaje = 'comando';
console.log('[N03] tipo:', tipo_mensaje, '| txt:', texto.substring(0,50));
return [{json:{remitente, texto, tipo_mensaje, timestamp, audio_base64, audio_mimetype, comando_especial, message_id: key.id || ''}}];

// N04b — Transcripción de audio con Whisper
const item = $input.first();
const audioBase64 = item.json.audio_base64 || '';
const mimetype = item.json.audio_mimetype || 'audio/ogg';

if (!audioBase64) {
  return [{json:{...item.json, texto:'[Audio vacío]', tipo_mensaje:'texto'}}];
}

const apiKey = $env.OPENAI_API_KEY || '';
if (!apiKey) {
  return [{json:{...item.json, texto:'[OpenAI Key no configurada]', tipo_mensaje:'texto'}}];
}

try {
  const audioBuffer = Buffer.from(audioBase64, 'base64');
  const ext = mimetype.includes('mp4') ? 'mp4' : mimetype.includes('mpeg') ? 'mp3' : 'ogg';
  const boundary = '----FormBoundary' + Math.random().toString(36).slice(2);

  const header = Buffer.from(
    `--${boundary}\r\nContent-Disposition: form-data; name="model"\r\n\r\nwhisper-1\r\n` +
    `--${boundary}\r\nContent-Disposition: form-data; name="language"\r\n\r\nes\r\n` +
    `--${boundary}\r\nContent-Disposition: form-data; name="file"; filename="audio.${ext}"\r\nContent-Type: ${mimetype}\r\n\r\n`
  );
  const footer = Buffer.from(`\r\n--${boundary}--\r\n`);
  const body = Buffer.concat([header, audioBuffer, footer]);

  const response = await fetch('https://api.openai.com/v1/audio/transcriptions', {
    method: 'POST',
    headers: {
      'Authorization': 'Bearer ' + apiKey,
      'Content-Type': `multipart/form-data; boundary=${boundary}`,
      'Content-Length': body.length.toString()
    },
    body
  });

  const result = await response.json();
  const transcripcion = result.text || '[No se pudo transcribir]';
  console.log('[SOA-N04b] Transcripción OK:', transcripcion.substring(0,80));
  return [{json:{...item.json, texto: transcripcion, tipo_mensaje:'texto'}}];

} catch(e) {
  console.log('[SOA-N04b] Error:', e.message);
  return [{json:{...item.json, texto:'[Error transcripción: ' + e.message + ']', tipo_mensaje:'texto'}}];
}

// N04c — Manejar comandos especiales
const fs = require('fs');
const path = require('path');
const item = $input.first();
const comando = item.json.comando_especial;
const SOA_BASE = '/home/node/soa';
let mensaje_wa = '';

try {
  if (comando === 'REINICIAR') {
    // Borrar archivos temporales
    ['temp/iteraciones.json','temp/evasiones.json'].forEach(f => {
      try { fs.unlinkSync(path.join(SOA_BASE, f)); } catch(e){}
    });
    fs.writeFileSync(path.join(SOA_BASE,'temp/iteraciones.json'), JSON.stringify({ia1_ia2:0,ia3:0}));
    fs.writeFileSync(path.join(SOA_BASE,'temp/evasiones.json'), JSON.stringify({ia1:0,ia2:0,ia3:0}));
    mensaje_wa = '♻️ *SOA reiniciado*\n\nContadores de iteraciones y evasiones limpiados.\nEl sistema está listo para una nueva tarea.';
    console.log('[SOA-CMD] REINICIAR ejecutado');

  } else if (comando === 'ROLLBACK') {
    const rollbackDir = path.join(SOA_BASE, 'rollback');
    const archivos = fs.existsSync(rollbackDir) ? 
      fs.readdirSync(rollbackDir).filter(f => f.endsWith('.bak')).sort().reverse() : [];

    if (archivos.length === 0) {
      mensaje_wa = '⚠️ *Rollback fallido*\n\nNo hay backups disponibles.';
    } else {
      const ultimo = archivos[0];
      const nombreOriginal = ultimo.replace(/_\d{8}_\d{6}\.bak$/, '');
      const src = path.join(rollbackDir, ultimo);
      const dst = path.join(SOA_BASE, 'output', nombreOriginal);
      fs.copyFileSync(src, dst);
      mensaje_wa = '⏪ *Rollback exitoso*\n\nArchivo restaurado: ' + nombreOriginal + '\nBackup: ' + ultimo;
      console.log('[SOA-CMD] ROLLBACK →', nombreOriginal);
    }

  } else if (comando === 'STOP') {
    mensaje_wa = '⏹️ *SOA detenido*\n\nEl flujo actual fue cancelado.\nEnvía una nueva tarea cuando estés listo.';
    console.log('[SOA-CMD] STOP ejecutado');
  }
} catch(e) {
  mensaje_wa = '❌ Error al ejecutar comando ' + comando + ': ' + e.message;
  console.error('[SOA-CMD] Error:', e.message);
}

return [{json:{...item.json, mensaje_wa, ir_a_notificar: true}}];

// N05 — Preparar contexto completo para las IAs
const fs = require('fs');
const path = require('path');
const item = $input.first();
const SOA_BASE = '/home/node/soa';
const leerArchivo = (ruta, defecto = '') => { try { return fs.readFileSync(ruta, 'utf8'); } catch(e) { return defecto; } };

const contexto_proyecto = leerArchivo(path.join(SOA_BASE, 'context/contexto_proyecto.txt'), '[Sin contexto de proyecto]');
const contexto_sesion   = leerArchivo(path.join(SOA_BASE, 'context/contexto_sesion.txt'), '[Primera sesion]');
const archivo_activo    = leerArchivo(path.join(SOA_BASE, 'workspace/archivo_activo.txt'), '').trim();

let contenido_archivo_activo = '';
if (archivo_activo) {
  contenido_archivo_activo = leerArchivo(path.join(SOA_BASE,'output',archivo_activo), '') ||
                              leerArchivo(path.join(SOA_BASE,'workspace',archivo_activo), '[Archivo no encontrado]');
}

const modelo_ia1 = $env.MODEL_IA1 || 'meta-llama/llama-3.3-70b-instruct:free';
const modelo_ia2 = $env.MODEL_IA2 || 'google/gemma-3-27b-it:free';
const modelo_ia3 = $env.MODEL_IA3 || 'mistralai/mistral-7b-instruct:free';

let config = {
  ciclo:{ max_iteraciones_ia1_ia2:10, max_iteraciones_ia3:5 },
  extractor:{ blancos_previos_marcador:1, blancas_corte_sugerencias:3, blancos_fin_archivo:5, max_lineas_no_item:10, http_timeout_ms:120000 },
  modelos:{ ia1: modelo_ia1, ia2: modelo_ia2, ia3: modelo_ia3 }
};
try {
  const cfgLeido = JSON.parse(leerArchivo(path.join(SOA_BASE,'soa_config.json'), '{}'));
  if (cfgLeido && Object.keys(cfgLeido).length > 0) config = {...config, ...cfgLeido};
  config.modelos = { ia1: modelo_ia1, ia2: modelo_ia2, ia3: modelo_ia3 };
} catch(e){}

try {
  if (!fs.existsSync(path.join(SOA_BASE,'temp'))) fs.mkdirSync(path.join(SOA_BASE,'temp'),{recursive:true});
} catch(e){}

// FIX: solo resetear contadores si es un mensaje NUEVO (no viene del bucle IA3)
// Si viene de N16 (IA3 tiene sugerencias), item.json tiene 'sugerencias' array
const vieneDeIA3 = Array.isArray(item.json.sugerencias) && item.json.sugerencias.length > 0;
if (!vieneDeIA3) {
  try {
    fs.writeFileSync(path.join(SOA_BASE,'temp/iteraciones.json'), JSON.stringify({ia1_ia2:0,ia3:0}));
    fs.writeFileSync(path.join(SOA_BASE,'temp/evasiones.json'),   JSON.stringify({ia1:0,ia2:0,ia3:0}));
    console.log('[N05] Contadores reseteados — mensaje nuevo');
  } catch(e){ console.error('[N05] Error reseteando contadores:', e.message); }
}

// FIX: unificar sugerencias_ia3 y sugerencias (el output de N15b usa 'sugerencias')
const sugerencias_ia3 = item.json.sugerencias_ia3 || item.json.sugerencias || null;

let tarea_usuario = item.json.texto || item.json.tarea_usuario || '';
if (sugerencias_ia3 && sugerencias_ia3.length > 0) {
  tarea_usuario = 'Aplicar mejoras de IA3 al archivo ' + (archivo_activo || 'activo') + ':\n' +
    sugerencias_ia3.map((s,i) => (i+1)+'. '+s).join('\n');
  console.log('[N05] Tarea viene de sugerencias IA3, archivo:', archivo_activo);
}

console.log('[N05] modelos | ia1:', modelo_ia1, '| ia2:', modelo_ia2, '| ia3:', modelo_ia3);
console.log('[N05] tarea:', tarea_usuario.substring(0,80));

return [{json:{
  tarea_usuario,
  remitente: item.json.remitente || '',
  contexto_proyecto,
  contexto_sesion,
  archivo_activo,
  contenido_archivo_activo,
  config,
  iteracion_actual: 0
}}];

// N07 — Extrae respuesta IA1 + recupera contexto perdido por HTTP Request
// El nodo HTTP Request reemplaza el input con la respuesta API — hay que recuperar
// el contexto original desde N06pre
const item = $input.first();
const choices = item.json.choices || [];
let respuesta_ia1 = (choices[0]?.message?.content || '').trim();

// Strip thinking blocks (Qwen3, DeepSeek-R1, Nemotron los incluyen)
respuesta_ia1 = respuesta_ia1.replace(/<think>[\s\S]*?<\/think>/gi, '').trim();

// Recuperar contexto original (config, tarea_usuario, remitente, etc.)
const contexto = $('N06pre Preparar Body IA1').item.json;

console.log('[N07] respuesta_ia1:', respuesta_ia1.substring(0,120));
return [{ json: { ...contexto, respuesta_ia1 } }];

// N07b — Lógica Anti-Evasión IA1 (Parche 08 + fix modelos free)
const fs = require('fs');
const path = require('path');
const SOA_BASE = '/home/node/soa';
const item = $input.first();
const respuesta = (item.json.respuesta_ia1 || '').trim();
const contexto = item.json;

const FRASES_EVASION = [
  'necesito más información','necesito más contexto','podría aclarar',
  'no tengo acceso','como ia,','como modelo de ia','no puedo acceder',
  'i need more','could you clarify','i cannot','please provide',
  'necesito que me','lamentablemente','lo siento, pero','i apologize',
  'sin embargo, no','desafortunadamente'
];

// FIX: usar .includes() en lugar de .startsWith() para modelos que añaden preámbulo
const FORMATOS_VALIDOS = ['SCRIPTS:','APROBADO:','RECHAZADO:'];

function esEvasion(resp) {
  if (resp.length < 20) return true;
  const rl = resp.toLowerCase();
  for (const f of FRASES_EVASION) { if (rl.includes(f)) return true; }
  // FIX: includes() en lugar de startsWith() — modelos free añaden texto antes del formato
  for (const fmt of FORMATOS_VALIDOS) { if (resp.includes(fmt)) return false; }
  return true;
}

const evadir = esEvasion(respuesta);

if (!evadir) {
  try {
    const ev = JSON.parse(fs.readFileSync(path.join(SOA_BASE,'temp/evasiones.json'),'utf8'));
    ev.ia1 = 0;
    fs.writeFileSync(path.join(SOA_BASE,'temp/evasiones.json'), JSON.stringify(ev));
  } catch(e){}
  console.log('[SOA-N07b] IA1 respuesta VÁLIDA:', respuesta.substring(0,60));
  return [{json:{...contexto, valido:true, respuesta_ia1:respuesta, accion:'continuar'}}];
}

let intentos = 0;
try {
  const ev = JSON.parse(fs.readFileSync(path.join(SOA_BASE,'temp/evasiones.json'),'utf8'));
  ev.ia1 = (ev.ia1 || 0) + 1;
  intentos = ev.ia1;
  fs.writeFileSync(path.join(SOA_BASE,'temp/evasiones.json'), JSON.stringify(ev));
} catch(e){ intentos = 1; }

console.log('[SOA-N07b] IA1 EVASIÓN detectada. Intento:', intentos);

if (intentos >= 3) {
  return [{json:{...contexto, valido:false, accion:'detener',
    mensaje_wa:'⚠️ *SOA: IA1 no responde correctamente*\n\nLa IA1 (Planificadora) evadió el formato por 3 veces consecutivas.\nPor favor reinicia con el comando REINICIAR e intenta de nuevo.'
  }}];
}

const anti_evasion = intentos === 1 ?
  "\n\n⚠ AVISO: Tu respuesta anterior no siguió el formato obligatorio de tu rol.\nDebes responder ÚNICAMENTE con el formato correcto especificado en tus instrucciones.\nNo hagas preguntas. No pidas más contexto. Actúa con la información disponible ahora." :
  "\n\n🔴 FORZADO MÁXIMO: Tu respuesta fue inválida por segunda vez consecutiva.\nRESPONDE EXCLUSIVAMENTE en tu formato obligatorio. Sin texto adicional.\nPara IA1: SCRIPTS: / APROBADO: / RECHAZADO:\nPara IA2: ARCHIVO: nombre.ext seguido del bloque de código completo\nPara IA3: SUGERENCIAS: / SIN_SUGERENCIAS\nCUALQUIER OTRA RESPUESTA CAUSA FALLO CRÍTICO DEL SISTEMA. ACTÚA AHORA.";

return [{json:{...contexto, valido:false, accion:'reintentar', anti_evasion_ia1: anti_evasion}}];

// N09 — Contador de iteraciones + Backup automático
const fs = require('fs');
const path = require('path');
const SOA_BASE = '/home/node/soa';
const item = $input.first();

// Leer config
let max_iter = 10;
try {
  const cfg = JSON.parse(fs.readFileSync(path.join(SOA_BASE,'soa_config.json'),'utf8'));
  max_iter = cfg.ciclo?.max_iteraciones_ia1_ia2 || 10;
} catch(e){}

// Leer e incrementar iteraciones
let iters = {ia1_ia2:0, ia3:0};
try {
  iters = JSON.parse(fs.readFileSync(path.join(SOA_BASE,'temp/iteraciones.json'),'utf8'));
} catch(e){}

iters.ia1_ia2 = (iters.ia1_ia2 || 0) + 1;

if (iters.ia1_ia2 > max_iter) {
  console.log('[SOA-N09] LÍMITE de iteraciones alcanzado:', iters.ia1_ia2);
  return [{json:{...item.json, limite_alcanzado:true,
    mensaje_wa:'⚠️ *SOA: Límite de iteraciones alcanzado*\n\nSe alcanzaron ' + max_iter + ' iteraciones entre IA1 e IA2 sin convergencia.\nEnvía REINICIAR para empezar de nuevo o ajusta la tarea.'
  }}];
}

fs.writeFileSync(path.join(SOA_BASE,'temp/iteraciones.json'), JSON.stringify(iters));
console.log('[SOA-N09] Iteración IA1-IA2:', iters.ia1_ia2, '/', max_iter);

// Backup del archivo activo
const archivo_activo = (item.json.archivo_activo || '').trim();
let ruta_backup = '';

if (archivo_activo) {
  try {
    const srcDir = fs.existsSync(path.join(SOA_BASE,'output',archivo_activo)) ? 'output' : 'workspace';
    const src = path.join(SOA_BASE, srcDir, archivo_activo);
    if (fs.existsSync(src)) {
      const rollbackDir = path.join(SOA_BASE,'rollback');
      if (!fs.existsSync(rollbackDir)) fs.mkdirSync(rollbackDir, {recursive:true});
      const ts = new Date().toISOString().replace(/[-:T]/g,'').replace(/\.\d+Z/,'');
      const baseName = path.basename(archivo_activo, path.extname(archivo_activo));
      const backupName = baseName + '_' + ts + '.bak';
      ruta_backup = path.join(rollbackDir, backupName);
      fs.copyFileSync(src, ruta_backup);
      console.log('[SOA-N09] Backup creado:', backupName);
    }
  } catch(e){ console.error('[SOA-N09] Error en backup:', e.message); }
}

return [{json:{...item.json, limite_alcanzado:false, ruta_backup, iteracion_ia1_ia2: iters.ia1_ia2}}];

// N11 — Extrae respuesta IA2 + recupera contexto perdido por HTTP Request
const item = $input.first();
const choices = item.json.choices || [];
let respuesta_ia2 = (choices[0]?.message?.content || '').trim();

// Strip thinking blocks
respuesta_ia2 = respuesta_ia2.replace(/<think>[\s\S]*?<\/think>/gi, '').trim();

// Recuperar contexto original de N10pre
const contexto = $('N10pre Preparar Body IA2').item.json;

console.log('[N11] respuesta_ia2:', respuesta_ia2.substring(0,120));
return [{ json: { ...contexto, respuesta_ia2 } }];

// N11 — Detector Anti-Evasión IA2 + Extractor v4 + FIX rutas absolutas (P08+P18+FIX-RUTA)
const fs = require('fs');
const path = require('path');
const SOA_BASE = '/home/node/soa';
const item = $input.first();
const respuesta = (item.json.respuesta_ia2 || '').trim();
const config = item.json.config || {};

// ── FIX: Normalizar ruta absoluta o con prefijo → relativa ───────────────
function normalizarRuta(rawName) {
  let n = rawName || '';
  n = n.replace(/^\/home\/[^\/]+\/soa\/output\//, '');
  n = n.replace(/^\/home\/node\/soa\/output\//, '');
  n = n.replace(/^\/home\/node\/soa\/workspace\//, '');
  n = n.replace(/^\//, '');
  n = n.replace(/^output\//, '');   // ← FIX: evita output/output/login.html
  return n;
}

// ── Extractor de bloque v4 (Parche 18) ──────────────────────────────────
function extraerBloqueArchivo(resp, cfg) {
  const blancos_previos = cfg.extractor?.blancos_previos_marcador ?? 1;
  const blancos_fin = cfg.extractor?.blancos_fin_archivo ?? 5;
  const lineas = resp.split('\n');
  let nombre_archivo = '';
  let dentro_bloque = false;
  let tipo_delim = null;
  let heredoc_marker = '';
  let contenido = [];
  let blancos_consec = 0;

  for (let i = 0; i < lineas.length; i++) {
    const l = lineas[i];
    const lt = l.trim();

    if (!nombre_archivo) {
      if (lt.startsWith('ARCHIVO:')) {
        nombre_archivo = lt.replace('ARCHIVO:', '').trim();
      }
      continue;
    }

    if (!dentro_bloque) {
      if (lt.startsWith('```')) {
        tipo_delim = 'backtick'; dentro_bloque = true; continue;
      }
      const hm = lt.match(/^<<([A-Z_]+)/);
      if (hm) { tipo_delim = 'heredoc'; heredoc_marker = hm[1]; dentro_bloque = true; continue; }
      continue;
    }

    if (tipo_delim === 'backtick' && lt === '```') break;
    if (tipo_delim === 'heredoc' && lt === heredoc_marker) break;

    if (lt === '') {
      blancos_consec++;
      contenido.push(l);
    } else {
      const es_marcador = /^(---|Nota:|Fin |End |Observaci[oó]n:)/i.test(lt);
      if (es_marcador && blancos_consec >= blancos_previos) {
        while (contenido.length > 0 && contenido[contenido.length - 1].trim() === '') contenido.pop();
        break;
      }
      blancos_consec = 0;
      contenido.push(l);
    }
    if (blancos_consec >= blancos_fin) {
      while (contenido.length > 0 && contenido[contenido.length - 1].trim() === '') contenido.pop();
      break;
    }
  }
  return { nombre_archivo, contenido: contenido.join('\n') };
}

// ── Anti-evasión IA2 ─────────────────────────────────────────────────────
const FRASES_EVASION = [
  'necesito más', 'como ia', 'no puedo', 'no tengo acceso', 'i need', 'i cannot',
  'please provide', 'lamentablemente', 'lo siento', 'i apologize', 'desafortunadamente'
];

function esEvasion(resp) {
  if (resp.length < 20) return true;
  if (!resp.includes('ARCHIVO:')) return true;
  const rl = resp.toLowerCase();
  for (const f of FRASES_EVASION) {
    if (rl.includes(f) && !resp.startsWith('ARCHIVO:')) return true;
  }
  return false;
}

const evadir = esEvasion(respuesta);

if (!evadir) {
  try {
    const ev = JSON.parse(fs.readFileSync(path.join(SOA_BASE, 'temp/evasiones.json'), 'utf8'));
    ev.ia2 = 0;
    fs.writeFileSync(path.join(SOA_BASE, 'temp/evasiones.json'), JSON.stringify(ev));
  } catch(e) {}

  let { nombre_archivo, contenido } = extraerBloqueArchivo(respuesta, config);

  if (!nombre_archivo || !contenido.trim()) {
    return [{ json: { ...item.json, valido: false, accion: 'detener',
      mensaje_wa: '❌ *SOA: IA2 entregó archivo vacío*\n\nNo se pudo extraer el contenido.\nEnvía REINICIAR e intenta de nuevo.'
    }}];
  }

  // Normalizar la ruta antes de guardar
  nombre_archivo = normalizarRuta(nombre_archivo);

  try {
    const outputDir = path.join(SOA_BASE, 'output');
    const ruta_output = path.join(outputDir, nombre_archivo);

    // Crear subdirectorios si no existen (ej: ProyectoAlpha/index.html)
    const subDir = path.dirname(ruta_output);
    if (!fs.existsSync(subDir)) fs.mkdirSync(subDir, { recursive: true });

