// ── Extractor de sugerencias v4 (Parche 18) ──
function extraerSugerencias(resp, cfg) {
  const blancas_corte = cfg.extractor?.blancas_corte_sugerencias ?? 3;
  if (resp.trim() === 'SIN_SUGERENCIAS') return { sin_sugerencias: true, sugerencias: [] };
  if (!resp.trim().startsWith('SUGERENCIAS:')) return { sin_sugerencias: false, sugerencias: [], error: 'formato inválido' };
  const contenido = resp.replace(/^SUGERENCIAS:\s*/i, '');
  const lineas = contenido.split('\n');
  const sugerencias = [];
  let actual = '';
  let blancos = 0;
  for (const linea of lineas) {
    if (linea.trim() === '') {
      blancos++;
      if (blancos >= blancas_corte) break;
      continue;
    }
    blancos = 0;
    const m = linea.trim().match(/^(\d+)[.)\-]\s+(.+)/);
    if (m) {
      if (actual) sugerencias.push(actual.trim());
      actual = m[2];
    } else if (actual) {
      actual += ' ' + linea.trim();
    }
  }
  if (actual) sugerencias.push(actual.trim());

  // ── NUEVO: Filtrar sugerencias que ya estaban en el ciclo anterior ──
  const sugerenciasPrevias = item.json.sugerencias_previas_ia3 || [];
  const sugerenciasFiltradas = sugerencias.filter(s => {
    const sNorm = s.toLowerCase().trim();
    return !sugerenciasPrevias.some(prev => {
      const prevNorm = prev.toLowerCase().trim();
      // Considera duplicada si comparten más del 60% de palabras clave
      const palabrasS = sNorm.split(/\s+/);
      const palabrasPrev = prevNorm.split(/\s+/);
      const comunes = palabrasS.filter(p => p.length > 4 && palabrasPrev.includes(p));
      return comunes.length >= 3;
    });
  });

  console.log('[SOA-N15] Sugerencias originales:', sugerencias.length, '| Tras filtro de repetidas:', sugerenciasFiltradas.length);
  return { sin_sugerencias: sugerenciasFiltradas.length === 0, sugerencias: sugerenciasFiltradas };
}

