      JSON.stringify({ ia1: 0, ia2: 0, ia3: 0 }, null, 2), 'utf8');
    logs.push('[N18] ✅ Contadores reseteados');
  } catch(e) { logs.push('[N18] ⚠ Error reseteando contadores: ' + e.message); }

